class MainForm : Form
{
    private StatusStrip statusStrip;

    public MainForm()
    {
        statusStrip = new StatusStrip();
        // .NET 9 changed the default renderer for StatusStrip.
        // Explicitly set RenderMode to restore the .NET 8 appearance.
        statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(statusStrip);
    }
}

using System.Windows.Forms.Design;

class MyDropDownEditor
{
    // In .NET 9, IWindowsFormsEditorService.DropDownControl parameter changed
    // from nullable to non-nullable. Guard against passing null.
    public void CloseDropDown(IWindowsFormsEditorService editorService)
    {
        // Before (.NET 8): editorService.DropDownControl(null) was allowed to close.
        // After (.NET 9): parameter is non-nullable; call CloseDropDown() instead.
        editorService.CloseDropDown();
    }

    public void ShowDropDown(IWindowsFormsEditorService editorService,
                             System.Windows.Forms.Control? control)
    {
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }
}

